class PriorityQueue {
    constructor() {
        this.heap = [];
    }
    push(value) {
        this.heap.push(value);
        this.heapifyUp(this.heap.length - 1);
    }
    pop() {
        if (this.heap.length === 0) return [Infinity, -1];
        const result = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapifyDown(0);
        return result;
    }
    private heapifyUp(index) {
        let parent = Math.floor((index - 1) / 2);
        while (index > 0 && this.heap[index][0] < this.heap[parent][0]) {
            [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
            index = parent;
            parent = Math.floor((index - 1) / 2);
        }
    }
    private heapifyDown(index) {
        let left = 2 * index + 1;
        let right = 2 * index + 2;
        let smallest = index;
        if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
            smallest = left;
        }
        if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
            smallest = right;
        }
        if (smallest !== index) {
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            this.heapifyDown(smallest);
        }
    }
    get size() {
        return this.heap.length;
    }
}

function solve(n, edges) {
    const adj = new Array(n).fill().map(() => []);
    for (const edge of edges) {
        const [u, v, s, e] = edge;
        adj[u].push([v, s, e]);
    }

    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    const pq = new PriorityQueue();
    pq.push([0, 0]);

    while (pq.size() > 0) {
        const [currentTime, u] = pq.pop();
        if (u === n - 1) {
            return currentTime;
        }
        if (currentTime > dist[u]) {
            continue;
        }
        for (const [v, s, e] of adj[u]) {
            const t_edge = Math.max(currentTime, s);
            if (t_edge <= e) {
                const new_time = t_edge + 1;
                if (new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.push([new_time, v]);
                }
            }
        }
    }

    return -1;
